const item = $input.first().json;

// The OpenAI node's response shape can vary slightly by version, so read defensively.
const raw = item.message?.content || item.content || item.text || item.output || '{}';

let parsed = {};
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = {};
}

let fallbackEmail = '';
try {
  fallbackEmail = $('Meeting Request Email').first().json.from || '';
} catch (e) {
  // no email trigger data in this execution
}

return [{
  json: {
    name: parsed.name || '',
    email: parsed.email || fallbackEmail,
    purpose: parsed.purpose || '',
    requestedDate: parsed.requestedDate || '',
    requestedTime: parsed.requestedTime || '',
    duration: parsed.duration || 30,
    timezone: parsed.timezone || 'UTC',
    source: 'email'
  }
}];

const item = $input.first().json;
const tz = item.timezone || 'UTC';

let requestedStart = DateTime.fromFormat(`${item.requestedDate} ${item.requestedTime}`, 'yyyy-MM-dd HH:mm', { zone: tz });
if (!requestedStart.isValid) {
  requestedStart = DateTime.now().setZone(tz).plus({ hours: 2 }).set({ minute: 0, second: 0, millisecond: 0 });
}

const now = DateTime.now().setZone(tz);
const windowStart = (requestedStart < now ? now : requestedStart).toISO();
const windowEnd = requestedStart.plus({ days: 14 }).toISO();

return [{
  json: {
    ...item,
    requestedStart: requestedStart.toISO(),
    windowStart,
    windowEnd
  }
}];

const request = $('Compute Search Window').first().json;

// "Get Busy Times" can shape its output a couple of different ways depending
// on node version/options - normalize them all into a flat {start, end} list.
const busyPeriods = [];
for (const item of $input.all()) {
  const j = item.json;
  if (j.start && j.end) {
    busyPeriods.push({ start: j.start, end: j.end });
  } else if (Array.isArray(j.busy)) {
    for (const b of j.busy) busyPeriods.push({ start: b.start, end: b.end });
  } else if (j.calendars) {
    for (const cal of Object.values(j.calendars)) {
      for (const b of (cal.busy || [])) busyPeriods.push({ start: b.start, end: b.end });
    }
  }
}

const tz = request.timezone || 'UTC';
const durationMinutes = Number(request.duration) || 30;
const WORK_START_HOUR = 9;
const WORK_END_HOUR = 17;
const MAX_ALTERNATIVES = 3;

const overlaps = (aStart, aEnd, bStart, bEnd) => aStart < bEnd && bStart < aEnd;

let cursor = DateTime.fromISO(request.requestedStart, { zone: tz });
if (!cursor.isValid) cursor = DateTime.now().setZone(tz);

const searchLimit = cursor.plus({ days: 14 });
let found = null;
const alternatives = [];

while (cursor < searchLimit) {
  if (cursor.weekday <= 5) {
    const dayStart = cursor.set({ hour: WORK_START_HOUR, minute: 0, second: 0, millisecond: 0 });
    const dayEnd = cursor.set({ hour: WORK_END_HOUR, minute: 0, second: 0, millisecond: 0 });
    let slotStart = cursor > dayStart ? cursor : dayStart;

    while (slotStart.plus({ minutes: durationMinutes }) <= dayEnd) {
      const slotEnd = slotStart.plus({ minutes: durationMinutes });
      const busy = busyPeriods.some(b => overlaps(
        slotStart.toMillis(), slotEnd.toMillis(),
        DateTime.fromISO(b.start).toMillis(), DateTime.fromISO(b.end).toMillis()
      ));

      if (!busy) {
        if (!found) {
          found = { start: slotStart.toISO(), end: slotEnd.toISO() };
        } else if (alternatives.length < MAX_ALTERNATIVES) {
          alternatives.push({ start: slotStart.toISO(), end: slotEnd.toISO() });
        }
      }

      if (found && alternatives.length >= MAX_ALTERNATIVES) break;
      slotStart = slotStart.plus({ minutes: 15 });
    }
  }

  if (found && alternatives.length >= MAX_ALTERNATIVES) break;
  cursor = cursor.plus({ days: 1 }).set({ hour: 0, minute: 0, second: 0, millisecond: 0 });
}

return [{
  json: {
    ...request,
    slotFound: !!found,
    slotStart: found ? found.start : null,
    slotEnd: found ? found.end : null,
    alternativeSlots: alternatives
  }
}];

